    const projectedKeys=new Map<string,string[]>();for(const c of heads.filter(x=>x.kind==="anchor"&&x.action!=="remove")){const p=parse<Row>(c.payload),key=`${p.featureId}:${p.file}:${p.symbol??""}`;projectedKeys.set(key,[...(projectedKeys.get(key)??[]),c.natural_id]);}for(const [key,ids] of projectedKeys)if(ids.length>1)findings.push({severity:"hard",code:"duplicate_projection_key",subject:key,details:{candidateIds:ids.sort()}});const relationKeys=new Map<string,string[]>();for(const c of heads.filter(x=>x.kind==="relation"&&x.action!=="remove")){const p=parse<Row>(c.payload),key=`${p.fromId}:${p.toId}:${p.type}`;relationKeys.set(key,[...(relationKeys.get(key)??[]),c.natural_id]);}for(const [key,ids] of relationKeys)if(ids.length>1)findings.push({severity:"hard",code:"duplicate_projection_key",subject:key,details:{candidateIds:ids.sort()}});
    const parents=new Map(heads.filter(x=>x.kind==="feature"&&x.action!=="remove").map(x=>{const p=parse<Row>(x.payload);return [x.natural_id,p.parentId==null?null:String(p.parentId)] as const;}));for(const id of parents.keys()){const seen=new Set<string>();let cursor:string|null=id;while(cursor&&parents.has(cursor)){if(seen.has(cursor)){findings.push({severity:"hard",code:"hierarchy_cycle",subject:id,details:{cycle:[...seen,cursor]}});break;}seen.add(cursor);cursor=parents.get(cursor)??null;}}
    if(run.mode==="incremental"&&run.baseline_version_id){const projectedAnchors=new Map<string,Map<string,Row>>(),changed=this.db.prepare(`SELECT path,change_kind changeKind,previous_path previousPath FROM distill_inventory WHERE repo_id=? AND run_id=? AND change_kind IN ('modified','renamed','deleted')`).all(repoId,input.runId) as Row[],pruned=new Set<string>();for(const row of changed){pruned.add(row.path);if(row.changeKind==="renamed"&&row.previousPath)pruned.add(row.previousPath);}for(const row of this.db.prepare(`SELECT feature_id featureId,file,symbol FROM mapping_version_anchors WHERE repo_id=? AND version_id=?`).all(repoId,run.baseline_version_id) as Row[]){if(pruned.has(row.file))continue;const set=projectedAnchors.get(row.featureId)??new Map<string,Row>();set.set(`${row.file}\0${row.symbol??""}`,row);projectedAnchors.set(row.featureId,set);}for(const c of heads.filter(x=>x.kind==="anchor")){const p=parse<Row>(c.payload),key=`${p.file}\0${p.symbol??""}`,set=projectedAnchors.get(p.featureId)??new Map<string,Row>();if(c.action==="remove")set.delete(key);else set.set(key,p);projectedAnchors.set(p.featureId,set);}for(const feature of baselineFeatureRows)if(features.has(feature.id)&&(projectedAnchors.get(feature.id)?.size??0)===0)findings.push({severity:"review",code:"active_feature_lost_all_anchors",subject:feature.id,details:{baselineVersionId:run.baseline_version_id}});}
