    for(const c of heads.filter(x=>x.kind==="anchor")){const p=parse<Row>(c.payload),a={featureId:p.featureId,file:canonicalRepoPath(String(p.file)),symbol:p.symbol??"",lineStart:p.lineStart??null,lineEnd:p.lineEnd??null,contentHash:p.contentHash??null};if(c.action==="remove")anchorMap.delete(anchorKey(a));else anchorMap.set(anchorKey(a),a);}
